//! Claude (Anthropic) Provider Adapter
//!
//! 支持透传模式和 OpenAI Chat Completions 格式转换模式
//!
//! ## API 格式
//! - **anthropic** (默认): Anthropic Messages API 格式，直接透传
//! - **openai_chat**: OpenAI Chat Completions 格式，需要 Anthropic ↔ OpenAI 转换
//!
//! ## 认证模式
//! - **Claude**: Anthropic 官方 API (x-api-key + anthropic-version)
//! - **ClaudeAuth**: 中转服务 (仅 Bearer 认证，无 x-api-key)
//! - **OpenRouter**: 已支持 Claude Code 兼容接口，默认透传

use super::{AuthInfo, AuthStrategy, ProviderAdapter, ProviderType};
use crate::provider::Provider;
use crate::proxy::error::ProxyError;
use reqwest::RequestBuilder;

/// Claude 适配器
pub struct ClaudeAdapter;

/// Harmony models that require /v1/responses endpoint
/// These models use the Harmony response format (gpt-oss series)
const HARMONY_MODEL_PATTERNS: &[&str] = &["gpt-oss-", "openai/gpt-oss-"];

impl ClaudeAdapter {
    pub fn new() -> Self {
        Self
    }

    fn is_anthropic_model_id(model: &str) -> bool {
        let normalized = model.trim().to_lowercase();
        normalized.starts_with("claude-") || normalized.starts_with("anthropic/claude-")
    }

    /// Auto-detect OpenRouter model family.
    ///
    /// OpenRouter Claude-compatible endpoint works best for Anthropic Claude model IDs.
    /// If provider defaults are non-Anthropic model IDs (e.g. `openrouter/free`,
    /// `deepseek/...`), force OpenAI Chat transform mode.
    fn should_force_openai_chat_for_openrouter(&self, provider: &Provider) -> bool {
        if !self.is_openrouter(provider) {
            return false;
        }

        let Some(env) = provider
            .settings_config
            .get("env")
            .and_then(|v| v.as_object())
        else {
            return false;
        };

        let model_keys = [
            "ANTHROPIC_MODEL",
            "ANTHROPIC_REASONING_MODEL",
            "ANTHROPIC_DEFAULT_HAIKU_MODEL",
            "ANTHROPIC_DEFAULT_SONNET_MODEL",
            "ANTHROPIC_DEFAULT_OPUS_MODEL",
        ];

        let mut has_any_model = false;
        for key in model_keys {
            let Some(model) = env.get(key).and_then(|v| v.as_str()) else {
                continue;
            };
            let model = model.trim();
            if model.is_empty() {
                continue;
            }
            has_any_model = true;
            if !Self::is_anthropic_model_id(model) {
                return true;
            }
        }

        if !has_any_model {
            return false;
        }

        false
    }

    /// 获取供应商类型
    ///
    /// 根据 base_url 和 auth_mode 检测具体的供应商类型：
    /// - OpenRouter: base_url 包含 openrouter.ai
    /// - ClaudeAuth: auth_mode 为 bearer_only
    /// - Claude: 默认 Anthropic 官方
    pub fn provider_type(&self, provider: &Provider) -> ProviderType {
        // 检测 OpenRouter
        if self.is_openrouter(provider) {
            return ProviderType::OpenRouter;
        }

        // 检测 ClaudeAuth (仅 Bearer 认证)
        if self.is_bearer_only_mode(provider) {
            return ProviderType::ClaudeAuth;
        }

        ProviderType::Claude
    }

    /// 检测是否使用 OpenRouter
    fn is_openrouter(&self, provider: &Provider) -> bool {
        if let Ok(base_url) = self.extract_base_url(provider) {
            return base_url.contains("openrouter.ai");
        }
        false
    }

    /// 获取 API 格式
    ///
    /// 从 provider.meta.api_format 读取格式设置：
    /// - "anthropic" (默认): Anthropic Messages API 格式，直接透传
    /// - "openai_chat": OpenAI Chat Completions 格式，需要格式转换
    fn get_api_format(&self, provider: &Provider) -> &'static str {
        // OpenRouter with non-Anthropic model IDs must use OpenAI Chat format.
        // This guard intentionally overrides user meta.api_format="anthropic",
        // because Anthropic passthrough cannot serve those model families.
        if self.should_force_openai_chat_for_openrouter(provider) {
            return "openai_chat";
        }

        // 1) Preferred: meta.apiFormat (SSOT, never written to Claude Code config)
        if let Some(meta) = provider.meta.as_ref() {
            if let Some(api_format) = meta.api_format.as_deref() {
                return match api_format {
                    "openai_chat" => "openai_chat",
                    "anthropic" if self.should_force_openai_chat_for_opencode_zen(provider) => {
                        "openai_chat"
                    }
                    _ => "anthropic",
                };
            }
        }

        // 2) Backward compatibility: legacy settings_config.api_format
        if let Some(api_format) = provider
            .settings_config
            .get("api_format")
            .and_then(|v| v.as_str())
        {
            return match api_format {
                "openai_chat" => "openai_chat",
                "anthropic" if self.should_force_openai_chat_for_opencode_zen(provider) => {
                    "openai_chat"
                }
                _ => "anthropic",
            };
        }

        // 3) Backward compatibility: settings_config.apiFormat (camelCase)
        if let Some(api_format) = provider
            .settings_config
            .get("apiFormat")
            .and_then(|v| v.as_str())
        {
            return match api_format {
                "openai_chat" => "openai_chat",
                "anthropic" if self.should_force_openai_chat_for_opencode_zen(provider) => {
                    "openai_chat"
                }
                _ => "anthropic",
            };
        }

        // 4) OpenCode Zen mixed-endpoint compatibility:
        // If default mapped model is non-Claude (e.g. glm/kimi),
        // force OpenAI Chat routing even if old data still defaults to anthropic.
        if self.should_force_openai_chat_for_opencode_zen(provider) {
            return "openai_chat";
        }

        // 5) Backward compatibility: legacy openrouter_compat_mode (bool/number/string)
        let raw = provider.settings_config.get("openrouter_compat_mode");
        let enabled = match raw {
            Some(serde_json::Value::Bool(v)) => *v,
            Some(serde_json::Value::Number(num)) => num.as_i64().unwrap_or(0) != 0,
            Some(serde_json::Value::String(value)) => {
                let normalized = value.trim().to_lowercase();
                normalized == "true" || normalized == "1"
            }
            _ => false,
        };

        if enabled {
            "openai_chat"
        } else {
            "anthropic"
        }
    }

    fn is_opencode_zen_base_url(&self, provider: &Provider) -> bool {
        self.extract_base_url(provider)
